import socket, os
for path in ['/tmp/w311m1.sock','/tmp/w311q1.sock']:
    print('PATH', path, os.path.exists(path))
    if not os.path.exists(path):
        continue
    s=socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
    s.settimeout(2)
    s.connect(path)
    if path.endswith('m1.sock'):
        s.sendall(b'info status\nquit\n')
    else:
        s.sendall(b'{"execute":"qmp_capabilities"}\n{"execute":"query-status"}\n')
    out=b''
    try:
        while True:
            c=s.recv(4096)
            if not c:
                break
            out += c
    except Exception:
        pass
    print(out.decode('latin1','ignore'))
